<a-modal okType="default" title="Send emails" :visible="true" centered :footer="null" :class="state.modalWidth" @cancel="closeModal"><a-form class="px-4" ref="formRef" name="mailing" :model="state" :wrapper-col="{ span: 0 }" layout="vertical" @finish="handleFinish"><div class="mb-2">The email will be sent to the following addresses:</div><div class="overflow-auto mb-4 max-h-[150px]"><a-list class="w-full" size="small" bordered :data-source="state.users"><template #renderItem="{ item }"><a-list-item class="flex justify-start"><div class="w-14">{{ item.id }}</div><div>{{ item.mail }}</div></a-list-item></template></a-list></div><div>Total: {{ state.selectedUsersLength }}</div><a-divider></a-divider><a-form-item class="mb-2 w-full flex justify-end"><a-button class="absolute bottom-1 right-5" html-type="submit" :loading="state.loading">Enviar</a-button></a-form-item><a-alert v-if="state.success" message="Sent!" type="success"></a-alert><div class="p-4 bg-[#FFF2F0]" v-if="state.error"><div class="flex justify-between items-center"><div>The following emails could not be sent</div><a-button @click="handleViewErrorDetails()">See details</a-button></div><a-table class="mt-2 w-full" v-if="state.viewErrorDetails" :dataSource="state.sentMailErrors" :columns="columns" :pagination="false"></a-table></div></a-form></a-modal>